// test/vectors/ed25519_siggen.ts
//
// NIST ACVP EDDSA sigGen test vectors (ed25519 only).
//
// Source:
//   ACVP-Server/gen-val/json-files/EDDSA-SigGen-1.0/internalProjection.json
//   @see https://github.com/usnistgov/ACVP-Server/tree/master/gen-val/json-files/EDDSA-SigGen-1.0
//   algorithm=EDDSA, mode=sigGen, revision=1.0, isSample=true
//   ACVP-Server pin: 15c0f3deeefbfa8cb6cd32a99e1ca3b738c66bf0
//
// 4 ed25519 groups, 84 tests total. ed448 records are filtered
// out at transcription time.
//
// HashEdDSA corpus structure: ACVP merges Ed25519ph into the same sigGen
// JSON via per-group preHash flag (false/true). The per-record preHash
// discriminator surfaced here mirrors the mldsa_siggen.ts convention:
// preHash=null for pure (RFC 8032 §5.1.6), preHash='SHA-512' for prehash
// (RFC 8032 §5.1.7, dom2(F=1, ctx) || SHA-512(message)). Context is a
// per-record byte string, may be empty (RFC 8032 §5.1.6 pure with empty
// context is plain Ed25519, no dom2 prefix; pure with non-empty context
// is Ed25519ctx, dom2(F=0, ctx) prefix).
//
// sk (d) and pk (q) are shared within a testGroup in the ACVP shape;
// they are copied onto each per-test record here so the verifier does
// not need group-level lookups.

export type PreHash = null | 'SHA-512';

export interface SigGenVector {
	tcId:      number;
	tgId:      number;
	testType:  string;   // 'AFT' or 'BFT'
	preHash:   PreHash;  // null = pure Ed25519/Ed25519ctx, 'SHA-512' = Ed25519ph
	sk:        string;   // 32 bytes (d, the Ed25519 seed)
	pk:        string;   // 32 bytes (q, the encoded public key)
	message:   string;   // pre-prehash message bytes
	context:   string;   // ctx bytes (may be empty), <= 255 bytes
	signature: string;   // 64 bytes (R || s)
}

